            /// <summary>Writes a DecimalOffset32 to JSON as a hex string.</summary>
            public override void Write(Utf8JsonWriter writer, DecimalOffset32 value, JsonSerializerOptions options)
            {
                writer.WriteStringValue(value.ToString());
            }
        }


        // ── Opaque decimal ↔ UInt128 bit reinterpretation ──
        [MethodImpl(MethodImplOptions.AggressiveInlining)]
        private static decimal UInt128BitsToDecimal(UInt128 bits) => Unsafe.As<UInt128, decimal>(ref bits);
        [MethodImpl(MethodImplOptions.AggressiveInlining)]
        private static UInt128 DecimalToUInt128Bits(decimal value) => Unsafe.As<decimal, UInt128>(ref value);
    }
}
